css:
/* Layout & Direction */
.print-frame { 
    width: 100%; 
    border-collapse: collapse; 
    direction: rtl; 
    text-align: right; 
}
.print-format-container { padding: 10px; font-family: Arial, sans-serif; }

/* Header Titles */
.eiu-header-text { text-align: center; margin-bottom: 20px; }
.form-badge {
    display: inline-block;
    padding: 8px 25px;
    background: #f2f2f2;
    border: 1px solid #333;
    font-weight: bold;
    font-size: 16px;
}

.section-title-box {
    background-color: #1a4d80;
    color: white;
    padding: 5px 12px;
    font-weight: bold;
    margin-top: 15px;
    border: 1px solid #1a4d80;
    text-align: right;
    font-size: 12px;
}

/* Table Styling */
.doc-table { width: 100%; border-collapse: collapse; margin-bottom: 0px; }
.doc-table th, .doc-table td {
    border: 1px solid #333;
    padding: 8px;
    font-size: 11px;
    text-align: right;
}
.doc-table th { background-color: #f2f2f2; font-weight: bold; width: 22%; }

/* items-table specific overrides */
.items-table thead th {
    background-color: #f2f2f2;
    text-align: center;
    border: 1px solid #333;
}

/* Signatures Grid (Flex Wrap) */
.signature-grid {
    display: flex;
    flex-wrap: wrap;
    justify-content: center;
    gap: 15px;
    margin-top: 30px;
    direction: rtl;
}
.sig-box { width: 22%; text-align: center; margin-bottom: 15px; }
.sig-name { 
    height: 25px; 
    font-weight: bold; 
    color: #1a4d80; 
    font-size: 10px; 
    display: flex; 
    align-items: flex-end; 
    justify-content: center; 
}
.sig-line { border-top: 1px solid #000; margin: 5px 0; }
.sig-box p { font-size: 9px; margin: 0; font-weight: bold; }

/* Footer */
.page-footer-wrapper { border-top: 1px solid #ccc; padding-top: 5px; margin-top: 15px; }
.page-footer { display: flex; justify-content: space-between; font-size: 9px; color: #666; direction: rtl; }

@media print {
    .print-frame thead { display: table-header-group; }
    .print-frame tfoot { display: table-footer-group; }
    body { margin: 0; padding: 0; }
}

/* 1. الأيقونات العامة (تظهر على الخلفية البيضاء أو الرمادية) */
.icon::before {
    font-family: "FontAwesome";
    display: inline-block;
    margin-left: 8px;
    font-weight: normal;
    color: #444444; /* رمادي غامق جداً للوضوح */
}

/* 2. الأيقونات داخل العناوين (تظهر فوق الخلفية الزرقاء) */
.section-title-box .icon::before {
    color: #ffffff !important; /* أبيض ناصع للوضوح فوق الأزرق */
}

